commands.script:
import time
import random
from app.utils.human_mouse import cdp_precise_click, smooth_move_mouse

ui = command_ui if isinstance(command_ui, dict) else {}
config = ui.get('values') if isinstance(ui.get('values'), dict) else ui

def _as_int(val, default):
    try:
        return int(val)
    except Exception:
        return default

def _as_float(val, default):
    try:
        return float(val)
    except Exception:
        return default

def _as_text(val, default):
    return str(val).strip() if val else default

def _sleep(sec, step=0.2):
    deadline = time.time() + max(0.0, float(sec or 0.0))
    while time.time() < deadline:
        raise_if_cancelled()
        reset_timeout()
        time.sleep(min(step, max(0.0, deadline - time.time())))
    raise_if_cancelled()
    reset_timeout()

def _probe_ele(selector, timeout=0.5):
    raise_if_cancelled()
    try:
        return tab.ele(selector, timeout=timeout)
    except Exception:
        return None

def _is_displayed(ele):
    try:
        return bool(ele and ele.states.is_displayed)
    except Exception:
        return False

def _click_element_center(ele, label, jitter=2, move_offset=36):
    raise_if_cancelled()
    if not ele:
        return False
    pos = None
    try:
        try:
            ele.scroll.to_see()
            _sleep(0.1, 0.05)
        except Exception:
            pass
        rect = ele.run_js("""
            const r = this.getBoundingClientRect();
            return {x: Math.round(r.left + r.width / 2), y: Math.round(r.top + r.height / 2), w: r.width, h: r.height};
        """)
        if isinstance(rect, dict) and float(rect.get('w') or 0) > 0 and float(rect.get('h') or 0) > 0:
            pos = (int(rect.get('x')), int(rect.get('y')))
    except Exception:
        pass
    if not pos:
        try:
            r = ele.rect
            for attr in ('viewport_midpoint', 'viewport_click_point', 'midpoint', 'click_point'):
                p = getattr(r, attr, None)
                if p and len(p) >= 2:
                    pos = (int(p[0]), int(p[1]))
                    break
        except Exception:
            pass
    if pos:
        cx = pos[0] + random.randint(-jitter, jitter)
        cy = pos[1] + random.randint(-jitter, jitter)
        logger.info(f"[Auto-Battle] \u51c6\u5907\u70b9\u51fb {label}: ({cx}, {cy})")
        try:
            smooth_move_mouse(tab, (cx - move_offset, cy - move_offset), (cx, cy), check_cancelled=check_cancelled)
        except TypeError:
            smooth_move_mouse(tab, (cx - move_offset, cy - move_offset), (cx, cy))
        _sleep(random.uniform(0.05, 0.12), 0.03)
        return bool(cdp_precise_click(tab, cx, cy, hold_duration=random.uniform(0.025, 0.055), check_cancelled=check_cancelled))
    try:
        result = ele.run_js("""
            try {
                this.scrollIntoView({block: 'center', inline: 'center', behavior: 'instant'});
                this.click();
                return true;
            } catch (error) {
                return false;
            }
        """)
        return bool(result)
    except Exception as e:
        logger.warning(f"[Auto-Battle] JS \u70b9\u51fb {label} \u5931\u8d25: {e}")
        return False

def _visible_vote_button_info():
    raise_if_cancelled()
    try:
        info = tab.run_js("""
            return (() => {
                const norm = (v) => String(v || '').replace(/\\s+/g, ' ').trim().toLowerCase();
                const vw = window.innerWidth || document.documentElement.clientWidth || 0;
                const vh = window.innerHeight || document.documentElement.clientHeight || 0;
                const visible = (el) => {
                    if (!(el instanceof HTMLElement) || !el.isConnected) return false;
                    const rect = el.getBoundingClientRect();
                    if (!rect || rect.width < 8 || rect.height < 8) return false;
                    if (rect.bottom <= 0 || rect.right <= 0 || rect.top >= vh || rect.left >= vw) return false;
                    const style = window.getComputedStyle(el);
                    if (style.display === 'none' || style.visibility === 'hidden' || Number(style.opacity || '1') <= 0.05) return false;
                    if (el.disabled || el.getAttribute('aria-disabled') === 'true') return false;
                    return true;
                };
                const matchesA = (text) => {
                    const t = norm(text);
                    return t.includes('a \u66f4\u597d') || t.includes('a is better') || t.includes('\U0001f448 a') || t.includes('\u2190 a') || t === 'a better';
                };
                const buttons = Array.from(document.querySelectorAll('button, [role="button"]'));
                for (const el of buttons) {
                    if (!visible(el)) continue;
                    const text = el.innerText || el.textContent || el.getAttribute('aria-label') || '';
                    if (!matchesA(text)) continue;
                    el.scrollIntoView({ block: 'center', inline: 'center', behavior: 'instant' });
                    const r = el.getBoundingClientRect();
                    return {found: true, text: String(text).replace(/\\s+/g, ' ').trim(), x: Math.round(r.left + r.width / 2), y: Math.round(r.top + r.height / 2), w: Math.round(r.width), h: Math.round(r.height)};
                }
                return {found: false};
            })();
        """)
        return info if isinstance(info, dict) else {'found': False}
    except Exception as e:
        logger.debug(f"[Auto-Battle] \u6295\u7968\u6309\u94ae JS \u63a2\u6d4b\u5931\u8d25\uff08\u5ffd\u7565\uff09: {e}")
        return {'found': False}

def _click_visible_vote_button():
    info = _visible_vote_button_info()
    if not info.get('found'):
        return False, info
    cx = int(info.get('x') or 0) + random.randint(-3, 3)
    cy = int(info.get('y') or 0) + random.randint(-2, 2)
    logger.info(f"[Auto-Battle] \u53d1\u73b0\u53ef\u89c1\u6295\u7968\u6309\u94ae: {info.get('text') or 'A'}\uff0c\u51c6\u5907\u70b9\u51fb ({cx}, {cy})")
    try:
        smooth_move_mouse(tab, (cx - 36, cy - 36), (cx, cy), check_cancelled=check_cancelled)
    except TypeError:
        smooth_move_mouse(tab, (cx - 36, cy - 36), (cx, cy))
    _sleep(random.uniform(0.05, 0.12), 0.03)
    ok = bool(cdp_precise_click(tab, cx, cy, hold_duration=random.uniform(0.025, 0.055), check_cancelled=check_cancelled))
    if ok:
        return True, info
    logger.warning("[Auto-Battle] CDP \u6295\u7968\u70b9\u51fb\u672a\u786e\u8ba4\uff0c\u6539\u7528\u9875\u9762\u5185\u53ef\u89c1\u6309\u94ae click() \u515c\u5e95")
    try:
        fallback = tab.run_js("""
            return (() => {
                const norm = (v) => String(v || '').replace(/\\s+/g, ' ').trim().toLowerCase();
                const visible = (el) => {
                    if (!(el instanceof HTMLElement) || !el.isConnected) return false;
                    const r = el.getBoundingClientRect();
                    const s = window.getComputedStyle(el);
                    return r.width >= 8 && r.height >= 8 && s.display !== 'none' && s.visibility !== 'hidden' && !el.disabled;
                };
                for (const el of Array.from(document.querySelectorAll('button, [role="button"]'))) {
                    const text = el.innerText || el.textContent || el.getAttribute('aria-label') || '';
                    const t = norm(text);
                    if (visible(el) && (t.includes('a \u66f4\u597d') || t.includes('a is better') || t.includes('\U0001f448 a') || t.includes('\u2190 a') || t === 'a better')) {
                        el.click();
                        return true;
                    }
                }
                return false;
            })();
        """)
        return bool(fallback), info
    except Exception as e:
        logger.error(f"[Auto-Battle] \u9875\u9762\u5185\u6295\u7968\u70b9\u51fb\u515c\u5e95\u5931\u8d25: {e}")
        return False, info

def _has_revealed_models():
    raise_if_cancelled()
    try:
        info = tab.run_js("""
            return (() => {
                const text = document.body ? (document.body.innerText || '') : '';
                const hasVote = Array.from(document.querySelectorAll('button, [role="button"]')).some((el) => {
                    const r = el.getBoundingClientRect();
                    if (r.width < 8 || r.height < 8) return false;
                    const t = String(el.innerText || el.textContent || '').replace(/\\s+/g, ' ').trim().toLowerCase();
                    return t.includes('a \u66f4\u597d') || t.includes('a is better') || t.includes('b \u66f4\u597d') || t.includes('b is better') || t.includes('\u90fd\u597d') || t.includes('both') || t.includes('\u90fd\u4e0d\u597d') || t.includes('bad');
                });
                const hasModel = /model\\s*[ab]|assistant\\s*[ab]|winner|\u83b7\u80dc|\u6a21\u578b|gpt|claude|gemini|deepseek|qwen|llama/i.test(text);
                return {hasVote, hasModel};
            })();
        """)
        return bool(isinstance(info, dict) and info.get('hasModel') and not info.get('hasVote'))
    except Exception:
        return False

total_runs = _as_int(config.get('total_runs'), 20)
prompt_text = _as_text(config.get('prompt_text'), "")
base_url = _as_text(config.get('base_url'), "https://arena.ai/text")
message_selector = _as_text(config.get('message_selector'), "css:textarea[name='message']")
send_selector = _as_text(config.get('send_selector'), "css:button[type='submit']")
vote_selector = _as_text(config.get('vote_selector'), "xpath://button[contains(., 'A \u66f4\u597d') or contains(., 'A is better') or contains(., 'A is Better') or contains(., '\U0001f448 A') or contains(., '\u2190 A')]")
new_chat_selector = _as_text(config.get('new_chat_selector'), "css:a[href='/text']")
agree_selector = _as_text(config.get('agree_selector'), "xpath://button[translate(text(), 'AGREE', 'agree')='agree']")
wait_reply_timeout_sec = _as_float(config.get('wait_reply_timeout_sec'), 180.0)
wait_poll_interval_sec = max(0.2, _as_float(config.get('wait_poll_interval_sec'), 0.5))
post_vote_settle_sec = _as_float(config.get('post_vote_settle_sec'), 0.4)
post_click_wait_sec = _as_float(config.get('post_click_wait_sec'), 1.5)

logger.info(f"[Auto-Battle] \u542f\u52a8\u81ea\u52a8\u76f2\u6d4b\u4e0e\u6a21\u578b\u7ffb\u724c\u6d41\u7a0b\uff0c\u8ba1\u5212\u6267\u884c\u6b21\u6570: {total_runs}")

for run_idx in range(total_runs):
    raise_if_cancelled()
    logger.info(f"[Auto-Battle] \u6b63\u5728\u6267\u884c\u7b2c {run_idx + 1}/{total_runs} \u6b21\u6d41\u7a0b...")

    current_url = ""
    try:
        current_url = str(tab.url or "").rstrip('/')
    except Exception:
        pass
    base_url_norm = base_url.rstrip('/')
    is_on_battle_page = current_url == base_url_norm or current_url.endswith("arena.ai/text") or current_url.endswith("arena.ai")

    if not is_on_battle_page:
        logger.info(f"[Auto-Battle] \u5f53\u524d\u4e0d\u5728 Battle \u9875\u9762\uff0c\u8df3\u8f6c\u5230 {base_url}...")
        tab.get(base_url)
        _sleep(1.2)
    else:
        new_chat_btn = _probe_ele(new_chat_selector, timeout=1.5)
        if _is_displayed(new_chat_btn):
            logger.info("[Auto-Battle] \u53d1\u73b0 New Chat \u6309\u94ae\uff0c\u5f00\u59cb\u65b0\u5bf9\u8bdd")
            if not _click_element_center(new_chat_btn, "New Chat", jitter=2, move_offset=32):
                logger.warning("[Auto-Battle] New Chat \u70b9\u51fb\u5931\u8d25\uff0c\u6539\u7528\u76f4\u63a5\u8df3\u8f6c\u91cd\u7f6e")
                tab.get(base_url)
            _sleep(1.0)
        else:
            logger.info(f"[Auto-Battle] \u672a\u627e\u5230\u53ef\u89c1 New Chat \u6309\u94ae\uff0c\u76f4\u63a5\u8df3\u8f6c {base_url} \u91cd\u7f6e\u5bf9\u8bdd")
            tab.get(base_url)
            _sleep(1.2)

    try:
        agree_btn = _probe_ele(agree_selector, timeout=1.0)
        if _is_displayed(agree_btn):
            logger.info("[Auto-Battle] \u68c0\u6d4b\u5230 Agree \u534f\u8bae\u5f39\u7a97\uff0c\u51c6\u5907\u70b9\u51fb")
            _click_element_center(agree_btn, "Agree", jitter=2, move_offset=28)
            _sleep(0.5)
    except Exception as e:
        logger.debug(f"[Auto-Battle] \u68c0\u67e5/\u70b9\u51fb Agree \u6309\u94ae\u53d1\u751f\u5f02\u5e38\uff08\u5ffd\u7565\uff09: {e}")

    raise_if_cancelled()
    reset_timeout()
    try:
        displayed = tab.wait.ele_displayed(message_selector, timeout=10.0)
        input_box = _probe_ele(message_selector, timeout=0.2) if displayed else None
    except Exception:
        input_box = _probe_ele(message_selector, timeout=0.5)

    if not input_box:
        logger.error("[Auto-Battle] \u627e\u4e0d\u5230\u8f93\u5165\u6846\uff0c\u8df3\u8fc7\u672c\u8f6e")
        continue

    logger.info("[Auto-Battle] \u6b63\u5728\u8f93\u5165\u63d0\u793a\u8bcd...")
    raise_if_cancelled()
    try:
        input_box.clear()
    except Exception:
        pass
    input_box.input(prompt_text)
    _sleep(0.3)

    send_btn = _probe_ele(send_selector, timeout=0.8)
    if not send_btn:
        send_btn = _probe_ele("xpath://button[contains(@aria-label, 'Send')]", timeout=0.5)

    raise_if_cancelled()
    if send_btn:
        logger.info("[Auto-Battle] \u6b63\u5728\u70b9\u51fb\u53d1\u9001\u6309\u94ae...")
        if not _click_element_center(send_btn, "\u53d1\u9001\u6309\u94ae", jitter=2, move_offset=24):
            try:
                send_btn.click()
            except Exception as e:
                logger.warning(f"[Auto-Battle] \u53d1\u9001\u6309\u94ae\u5e38\u89c4\u70b9\u51fb\u5931\u8d25\uff0c\u5c1d\u8bd5 Enter: {e}")
                input_box.input("\n")
    else:
        logger.warning("[Auto-Battle] \u672a\u627e\u5230\u53d1\u9001\u6309\u94ae\uff0c\u5c1d\u8bd5\u8f93\u5165 Enter \u952e\u53d1\u9001")
        input_box.input("\n")

    _sleep(0.8)

    logger.info("[Auto-Battle] \u7b49\u5f85\u4e24\u4fa7\u5927\u6a21\u578b\u751f\u6210\u5b8c\u6bd5\u5e76\u5c55\u793a\u6295\u7968\u6309\u94ae...")
    vote_btn_found = False
    poll_steps = max(1, int(wait_reply_timeout_sec / wait_poll_interval_sec))
    for sec in range(poll_steps):
        raise_if_cancelled()
        reset_timeout()
        info = _visible_vote_button_info()
        if info.get('found'):
            vote_btn_found = True
            logger.info(f"[Auto-Battle] \u53ef\u89c1\u6295\u7968\u6309\u94ae\u5df2\u5728\u7b2c {round(sec * wait_poll_interval_sec, 1)} \u79d2\u51fa\u73b0: {info.get('text') or 'A'}")
            break
        _sleep(wait_poll_interval_sec, min(0.2, wait_poll_interval_sec))

    if not vote_btn_found:
        logger.error("[Auto-Battle] \u7b49\u5f85\u56de\u590d\u8d85\u65f6\uff0c\u672a\u627e\u5230\u53ef\u89c1\u6295\u7968\u6309\u94ae\uff0c\u8df3\u8fc7\u672c\u8f6e\u3002")
        continue

    _sleep(post_vote_settle_sec, 0.1)
    clicked, info = _click_visible_vote_button()
    if not clicked:
        logger.warning("[Auto-Battle] \u53ef\u89c1\u6309\u94ae\u70b9\u51fb\u5931\u8d25\uff0c\u5c1d\u8bd5\u914d\u7f6e\u9009\u62e9\u5668\u515c\u5e95")
        vote_btn = _probe_ele(vote_selector, timeout=0.8)
        clicked = _click_element_center(vote_btn, "A \u66f4\u597d", jitter=3, move_offset=32)
    if not clicked:
        logger.error("[Auto-Battle] \u70b9\u51fb A \u66f4\u597d \u6309\u94ae\u5931\u8d25\uff0c\u8df3\u8fc7\u672c\u6b21\u6295\u7968\u3002")
        continue

    reveal_deadline = time.time() + max(0.5, post_click_wait_sec)
    reset_timeout()
    while time.time() < reveal_deadline:
        raise_if_cancelled()
        reset_timeout()
        if _has_revealed_models():
            logger.info("[Auto-Battle] \u6295\u7968\u540e\u6a21\u578b\u8eab\u4efd\u5df2\u63ed\u793a\u3002")
            break
        _sleep(0.25, 0.1)
    _sleep(0.5)
    logger.info(f"[Auto-Battle] \u7b2c {run_idx + 1} \u6b21\u76f2\u6d4b\u6d41\u7a0b\u7ed3\u675f\u3002")

logger.info("[Auto-Battle] \u6240\u6709\u76f2\u6d4b\u6d41\u7a0b\u5168\u90e8\u6267\u884c\u5b8c\u6210\uff01")
